  1	import React, { FC, useCallback } from 'react';
  2	
  3	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import DiskListTitle from '@kubevirt-utils/components/DiskListTitle/DiskListTitle';
  6	import DiskSourceSelect from '@kubevirt-utils/components/DiskModal/components/DiskSourceSelect/DiskSourceSelect';
  7	import DiskModal from '@kubevirt-utils/components/DiskModal/DiskModal';
  8	import { SourceTypes } from '@kubevirt-utils/components/DiskModal/utils/types';
  9	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 10	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 11	import { replaceTemplateVM } from '@kubevirt-utils/resources/template';
 12	import {
 13	  k8sUpdate,
 14	  ListPageFilter,
 15	  useListPageFilter,
 16	  VirtualizedTable,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 19	
 20	import useEditTemplateAccessReview from '../../hooks/useIsTemplateEditable';
 21	
 22	import DiskRow from './components/DiskRow';
 23	import useDiskColumns from './hooks/useDiskColumns';
 24	import useDisksFilters from './hooks/useDisksFilters';
 25	import useTemplateDisksTableData from './hooks/useTemplateDisksTableData';
 26	import { getTemplateVMWithNamespace } from './utils';
 27	
 28	import './TemplateDisksPage.scss';
 29	
 30	type TemplateDisksPageProps = {
 31	  obj: V1Template;
 32	};
 33	
 34	const TemplateDisksPage: FC<TemplateDisksPageProps> = ({ obj: template }) => {
 35	  const { createModal } = useModal();
 36	  const columns = useDiskColumns();
 37	  const [disks, disksLoaded] = useTemplateDisksTableData(template);
 38	  const filters = useDisksFilters();
 39	  const [data, filteredData, onFilterChange] = useListPageFilter(disks, filters);
 40	  const vm = getTemplateVMWithNamespace(template);
 41	
 42	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
 43	
 44	  const onSubmitTemplate = useCallback(
 45	    (updatedTemplate: V1Template) =>
 46	      k8sUpdate({
 47	        data: updatedTemplate,
 48	        model: TemplateModel,
 49	        name: updatedTemplate?.metadata?.name,
 50	        ns: updatedTemplate?.metadata?.namespace,
 51	      }),
 52	    [],
 53	  );
 54	
 55	  const onUpdate = useCallback(
 56	    async (updatedVM: V1VirtualMachine) => {
 57	      await onSubmitTemplate(replaceTemplateVM(template, updatedVM));
 58	    },
 59	    [onSubmitTemplate, template],
 60	  );
 61	
 62	  return (
 63	    <div className="template-disks-page">
 64	      <PageSection variant={PageSectionVariants.light}>
 65	        <SidebarEditor<V1Template> onResourceUpdate={onSubmitTemplate} resource={template}>
 66	          <DiskListTitle />
 67	          {isTemplateEditable && (
 68	            <DiskSourceSelect
 69	              onSelect={(diskSource: SourceTypes) => {
 70	                return createModal(({ isOpen, onClose }) => (
 71	                  <DiskModal
 72	                    createDiskSource={diskSource}
 73	                    isOpen={isOpen}
 74	                    onClose={onClose}
 75	                    onSubmit={onUpdate}
 76	                    vm={vm}
 77	                  />
 78	                ));
 79	              }}
 80	              className="list-page-create-button-margin"
 81	            />
 82	          )}
 83	          <ListPageFilter
 84	            data={data}
 85	            hideLabelFilter
 86	            loaded={disksLoaded}
 87	            onFilterChange={onFilterChange}
 88	            rowFilters={filters}
 89	          />
 90	          <VirtualizedTable
 91	            columns={columns}
 92	            data={filteredData}
 93	            loaded={disksLoaded}
 94	            loadError={undefined}
 95	            Row={DiskRow}
 96	            rowData={{ actionsDisabled: !isTemplateEditable, onUpdate, vm }}
 97	            unfilteredData={data}
 98	          />
 99	        </SidebarEditor>
100	      </PageSection>
101	    </div>
102	  );
103	};
104	
105	export default TemplateDisksPage;

